      title: 'Digital Transformation Success Story',
      industry: 'general',
      summary: 'Learn how organizations successfully navigate digital change.',
      url: 'https://yoursite.com/case-studies/digital-transformation',
      relevanceScore: 0.70
    }
  ];
} else {
  caseStudies = caseResult[0].json;
}

// Check if whitepapers API failed
