      whitepapers: whitepapersNode.all()[0]?.json?.error ? 'fallback' : 'api'
    }
  }
}];

// ── LOCAL ERROR HANDLING & ALERTING ──
const error = items[0].json;
const dealContext = $('Extract & Enrich Deal Context')?.first()?.json || {};

const errorPayload = {
