// ── INPUT VALIDATION & SANITIZATION ──
const payload = items[0].json.body || items[0].json;

const required = ['dealId'];
const missing = required.filter(f => !payload[f] || String(payload[f]).trim() === '');

if (missing.length > 0) {
  throw new Error(`VALIDATION_ERROR: Missing required fields: ${missing.join(', ')}`);
}

// Sanitize dealId (only alphanumeric and dashes)
const dealId = String(payload.dealId).replace(/[^a-zA-Z0-9\-]/g, '');
if (!dealId || dealId.length < 3) {
  throw new Error('VALIDATION_ERROR: Invalid dealId format');
}

// Correlation ID for tracing across systems
const correlationId = payload.correlationId || $execution.id;

return [{
  json: {
    dealId,
    stage: payload.stage || 'unknown',
    correlationId,
    receivedAt: new Date().toISOString(),
    sourceIp: $json.headers?.['x-forwarded-for'] || 'unknown',
    validated: true
  }
}];

// ── DEAL CONTEXT EXTRACTION WITH FALLBACKS ──
const deal = items[0].json;
const input = $('Validate Input Payload').first().json;

// Safe extraction helpers
const safe = (obj, path, fallback = null) => {
  try {
    return path.split('.').reduce((o, k) => (o || {})[k], obj) || fallback;
  } catch { return fallback; }
};

// Industry detection from description/keywords
const description = safe(deal, 'Description', '') + ' ' + safe(deal, 'Deal_Name', '');
const industryKeywords = {
  'saas': ['saas', 'software', 'cloud', 'platform', 'subscription'],
  'fintech': ['fintech', 'finance', 'banking', 'payment', 'crypto'],
  'healthcare': ['health', 'medical', 'pharma', 'clinic', 'patient'],
  'ecommerce': ['ecommerce', 'retail', 'shop', 'marketplace', 'online store'],
  'manufacturing': ['manufacturing', 'factory', 'industrial', 'production'],
  'education': ['education', 'e-learning', 'training', 'university', 'school']
};

let detectedIndustry = 'general';
const descLower = description.toLowerCase();
for (const [industry, keywords] of Object.entries(industryKeywords)) {
  if (keywords.some(k => descLower.includes(k))) {
    detectedIndustry = industry;
    break;
  }
}

// Deal stage mapping for content strategy
const stageContentMap = {
  'Qualification': 'awareness',
  'Needs Analysis': 'consideration', 
  'Proposal/Price Quote': 'decision',
  'Negotiation': 'decision',
  'Closed Won': 'onboarding',
  'Closed Lost': 'nurture'
};

const contentStage = stageContentMap[safe(deal, 'Stage')] || 'awareness';

// Pain point extraction (basic NLP)
const painIndicators = ['challenge', 'problem', 'issue', 'struggle', 'difficult', 'slow', 'manual', 'inefficient', 'costly', 'expensive'];
const detectedPainPoints = painIndicators.filter(p => descLower.includes(p));

// Decision maker level detection
const cLevelKeywords = ['ceo', 'cto', 'cfo', 'coo', 'vp', 'director', 'head of'];
const contactName = safe(deal, 'Contact_Name.name', '');
const isCLevel = cLevelKeywords.some(k => contactName.toLowerCase().includes(k));

const context = {
  dealId: input.dealId,
  dealName: safe(deal, 'Deal_Name', 'Unknown Deal'),
  stage: safe(deal, 'Stage', 'unknown'),
  contentStage,
  amount: safe(deal, 'Amount', 0),
  currency: safe(deal, 'Currency', 'USD'),
  description: safe(deal, 'Description', ''),
  leadSource: safe(deal, 'Lead_Source', 'unknown'),
  contactName,
  contactEmail: safe(deal, 'Contact_Name.email', ''),
  contactPhone: safe(deal, 'Contact_Name.phone', ''),
  accountName: safe(deal, 'Account_Name.name', ''),
  accountIndustry: safe(deal, 'Account_Name.industry', detectedIndustry),
  accountSize: safe(deal, 'Account_Name.employees', 'unknown'),
  detectedIndustry,
  detectedPainPoints: detectedPainPoints.length > 0 ? detectedPainPoints : ['general business challenges'],
  isCLevel,
  dealAge: safe(deal, 'Created_Time') ? Math.floor((Date.now() - new Date(deal.Created_Time).getTime()) / (1000 * 60 * 60 * 24)) : 0,
  correlationId: input.correlationId,
  extractedAt: new Date().toISOString()
};

return [{ json: context }];

