// ── AI OUTPUT VALIDATION & PARSING ──
const raw = items[0].json.content || items[0].json.output;

if (!raw) {
  throw new Error('AI_VALIDATION_ERROR: Empty response from AI model');
}

let parsed;
try {
  // Handle both direct JSON and markdown-wrapped JSON
  const text = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const jsonMatch = text.match(/```json\s*([\s\S]*?)```/) || text.match(/{[\s\S]*}/);
  const jsonString = jsonMatch ? jsonMatch[1] || jsonMatch[0] : text;
  parsed = JSON.parse(jsonString.trim());
} catch (e) {
  throw new Error(`AI_VALIDATION_ERROR: Failed to parse AI output - ${e.message}`);
}

// Schema validation
const required = ['recommendedCaseStudies', 'recommendedWhitepapers', 'emailContent'];
const missing = required.filter(f => !parsed[f]);
if (missing.length > 0) {
  throw new Error(`AI_VALIDATION_ERROR: Missing fields in AI output: ${missing.join(', ')}`);
}

// Validate email content
const email = parsed.emailContent;
if (!email?.subject || email.subject.length > 100) {
  throw new Error('AI_VALIDATION_ERROR: Invalid or missing email subject');
}
if (!email?.bodyHtml || email.bodyHtml.length < 50) {
  throw new Error('AI_VALIDATION_ERROR: Email body too short or missing');
}

// Validate recommendations count
if (!Array.isArray(parsed.recommendedCaseStudies) || parsed.recommendedCaseStudies.length === 0) {
  throw new Error('AI_VALIDATION_ERROR: No case studies recommended');
}
if (!Array.isArray(parsed.recommendedWhitepapers) || parsed.recommendedWhitepapers.length === 0) {
  throw new Error('AI_VALIDATION_ERROR: No whitepapers recommended');
}

// Add validation metadata
parsed._validation = {
  passed: true,
  validatedAt: new Date().toISOString(),
  caseStudyCount: parsed.recommendedCaseStudies.length,
  whitepaperCount: parsed.recommendedWhitepapers.length,
  emailLength: email.bodyHtml.length
};

return [{ json: parsed }];

// ── BUILD STRUCTURED PAYLOAD FOR AI ──
const deal = $('Extract & Enrich Deal Context').first().json;
const content = $('Fallback Content Loader').first().json;
const config = $('Content API Configuration').first().json;

// Validate content availability
if (!content.caseStudiesData || content.caseStudiesData.length === 0) {
  throw new Error('CONTENT_ERROR: No case studies available after fallback');
}
if (!content.whitepapersData || content.whitepapersData.length === 0) {
  throw new Error('CONTENT_ERROR: No whitepapers available after fallback');
}

// Build the recommendation context
const payload = {
  dealContext: {
    dealId: deal.dealId,
    dealName: deal.dealName,
    stage: deal.stage,
    contentStage: deal.contentStage,
    amount: deal.amount,
    currency: deal.currency,
    industry: deal.detectedIndustry,
    accountIndustry: deal.accountIndustry,
    accountSize: deal.accountSize,
    painPoints: deal.detectedPainPoints,
    isCLevel: deal.isCLevel,
    dealAge: deal.dealAge,
    description: deal.description?.substring(0, 500) // Limit to prevent token overflow
  },
  availableContent: {
    caseStudies: content.caseStudiesData.slice(0, config.maxRecommendations * 2),
    whitepapers: content.whitepapersData.slice(0, config.maxRecommendations * 2)
  },
  constraints: {
    maxCaseStudies: config.maxRecommendations,
    maxWhitepapers: config.maxRecommendations,
    tone: deal.isCLevel ? 'executive' : 'practitioner',
    language: 'fr', // ou dynamique selon le contact
    includeCTA: true
  },
  metadata: {
    correlationId: deal.correlationId,
    workflowVersion: '2.0.0',
    timestamp: new Date().toISOString()
  }
};

return [{ json: payload }];
